import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { Reveal } from '../hooks/useReveal';
import { Button, SectionTag, CircleBtn, StatBox, Badge, LiveDot } from '../components/UI';
import { ZONES, ZONE_META, SHOPS, FARES, INITIAL_MESSAGES } from '../data/constants';
import styles from './HomePage.module.css';

// 1. IMPORT YOUR IMAGES (Ensure these paths match your folder structure)
// import shopBg from '../assets/shop-bg.jpg';
// import autoBg from '../assets/auto-bg.jpg';

function HeroSection() {
  const { setPage } = useApp();
  const [activeNow] = useState(Math.floor(Math.random() * 40) + 22);

  return (
    <section className={styles.hero}>
      <div className={styles.grain} />
      <div className={styles.orb1} />
      <div className={styles.orb2} />
      <div className={styles.heroRight}>
        <div className={styles.heroRightFake}>
          {/* THE BUILDING PHOTO IS SET IN CSS VIA .heroRightFake */}
          <div className={styles.heroEmojis}>🏘️</div>
          <div className={styles.heroDeco1} />
          <div className={styles.heroDeco2} />
          <div className={styles.heroDeco3} />
        </div>
        <div className={styles.heroRightOverlay} />
      </div>
      <div className={styles.heroLeftOverlay} />

      <div className={styles.heroContent}>
        <div className={styles.heroEyebrow}>
          <LiveDot /> {activeNow} locals active now
        </div>
        <h1 className={styles.heroTitle}>
          Know Your<br />
          <em className={styles.heroEm}>Street.</em><br />
          Before You<br />
          Walk It.
        </h1>
        <p className={styles.heroSub}>
          Mohalla connects you with your neighbours — anonymously. Real shop prices, verified auto fares, safety alerts.
        </p>
        <div className={styles.heroBtns}>
          <Button variant="primary" size="lg" onClick={() => setPage('map')}>
            Explore Your Zone →
          </Button>
          <Button variant="outline" size="lg" onClick={() => setPage('shops')}>
            Browse Shops
          </Button>
        </div>
        <div className={styles.heroStats}>
          {[
            { num: '2.1K+', lbl: 'Shops reviewed' },
            { num: '980+',  lbl: 'Fares verified' },
            { num: '6',     lbl: 'Active zones' },
            { num: '430+',  lbl: 'Alerts shared' },
          ].map(s => (
            <div key={s.lbl} className={styles.heroStat}>
              <div className={styles.heroStatNum}>{s.num}</div>
              <div className={styles.heroStatLbl}>{s.lbl}</div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

function AboutSection() {
  const { setPage } = useApp();

  // 2. STATE FOR THE NAVIGATION ARROWS
  const [aboutIdx, setAboutIdx] = useState(0);

  const aboutContents = [
    "We are a hyperlocal network passionate about real information, community trust, and making every neighbourhood easier to navigate. No ads, no algorithms — just neighbours helping neighbours.",
    "Verified auto and rickshaw rates calculated by the community. Stop overpaying and start commuting with confidence.",
    "Real-time shop price tracking. Compare milk, oil, and grocery prices across your local vendors anonymously.",
    "Live safety alerts and neighborhood happenings. Stay informed about road closures, water updates, or local events.",
    "Complete anonymity. Your data stays yours. No phone number or personal tracking — just local utility."
  ];

  const handleNext = () => setAboutIdx((prev) => (prev + 1) % aboutContents.length);
  const handlePrev = () => setAboutIdx((prev) => (prev - 1 + aboutContents.length) % aboutContents.length);

  // 3. UPDATED CARDS WITH BACKGROUND IMAGES
  const cards = [
    { 
      bgImage: 'https://images.unsplash.com/photo-1534723452862-4c874018d66d?q=80&w=1000', 
      emoji: '🏪', 
      title: 'Build Local Trust', 
      sub: 'Shop ratings from real neighbours', 
      big: true 
    },
    { 
      bgImage: 'https://images.unsplash.com/photo-1567157577327-03a517d39755?q=80&w=1000', 
      emoji: '🛺', 
      title: 'Know the Real Fare', 
      sub: 'Verified auto rates', 
      big: false 
    },
    { 
      bg: '#1a100a', // Solid color for the alert card
      emoji: '⚠️', 
      title: 'Stay Safe', 
      sub: 'Live safety warnings', 
      big: false 
    },
  ];

  return (
    <section className={`${styles.section} ${styles.sectionWhite}`}>
      <div className={styles.aboutGrid}>
        <div>
          <SectionTag>About Mohalla</SectionTag>
          <h2 className={styles.sectionTitle}>Your Hyperlocal<br />Community Hub</h2>
          <div className={styles.aboutPhotos}>
            {cards.map((c, i) => (
              <Reveal key={i} delay={i * 100} style={{ gridColumn: c.big ? '1 / -1' : 'auto' }}>
                <div
                  className={styles.photoCard}
                  style={{ 
                    background: c.bg || 'none',
                    backgroundImage: c.bgImage ? `linear-gradient(rgba(0,0,0,0.5), rgba(0,0,0,0.8)), url(${c.bgImage})` : 'none',
                    backgroundSize: 'cover',
                    backgroundPosition: 'center',
                    aspectRatio: c.big ? '16/7' : '4/3' 
                  }}
                  onClick={() => setPage('shops')}
                >
                  <div className={styles.photoCardEmoji} style={{ fontSize: c.big ? 72 : 44 }}>
                    {c.emoji}
                  </div>
                  <div className={styles.photoCardOverlay}>
                    <div className={styles.photoCardTitle}>{c.title}</div>
                    <div className={styles.photoCardSub}>{c.sub}</div>
                  </div>
                </div>
              </Reveal>
            ))}
          </div>
        </div>

        <div className={styles.aboutRight}>
          {/* 4. DYNAMIC TEXT BASED ON STATE */}
          <p className={styles.sectionSub}>
            {aboutContents[aboutIdx]}
          </p>

          <div className={styles.aboutNav}>
            <CircleBtn onClick={handlePrev}>←</CircleBtn>
            <CircleBtn accent onClick={handleNext}>→</CircleBtn>
            {/* 5. DYNAMIC COUNTER (0/5) */}
            <span className={styles.aboutNavCount}>{aboutIdx + 1} / {aboutContents.length}</span>
          </div>
          <div className={styles.divider} />
          <div className={styles.statsGrid}>
            <StatBox icon="🏪" num="2,140+" label="Shops Reviewed" />
            <StatBox icon="🛺" num="980+" label="Fares Verified" />
            <StatBox icon="⚠️" num="430+" label="Alerts Shared" />
            <StatBox icon="👥" num="6" label="Active Zones" />
          </div>
        </div>
      </div>
    </section>
  );
}

// ... rest of the sections (Happenings, Zones, etc.) stay the same
